#!/usr/bin/env node
// SPDX-FileCopyrightText: Copyright (c) RapierCraft Studios
// SPDX-License-Identifier: AGPL-3.0-or-later
/**
 * scripts/build-repo-map.mjs — ForgeDock persistent repo map builder
 *
 * Builds a blob-hash-keyed orientation index for the repo codebase. Each file
 * entry stores: the git blob hash, statically parsed exports/symbols, and an
 * optional one-line purpose summary (generated by a model pass or deferred to
 * null). Summaries are nullable — all structural data is deterministic without
 * any model call.
 *
 * The map is persisted to ~/.forge/index/repo-map.json (local rebuildable cache)
 * and can be mirrored to the `forge-knowledge` orphan branch for hydration by
 * fresh clones and CI agents.
 *
 * KEY DESIGN: blob-hash keying answers the staleness question for free. A file
 * whose content has not changed has the same blob hash — its entry is reused.
 * Only files whose blob hash changed (or new files) are re-processed. This bounds
 * the incremental rebuild cost to actual churn, not tree size.
 *
 * ZERO DEPENDENCIES: Node.js built-ins only (fs, path, crypto, url, child_process).
 * No third-party packages, no tree-sitter, no vector store, no SQLite.
 *
 * COMPATIBLE with the `forge-knowledge` orphan branch layout used by the
 * knowledge-ledger milestone (#11). This script writes `repo-map.json`; the
 * knowledge-ledger uses `knowledge-ledger.json`. Both coexist on the same branch.
 *
 * Usage:
 *   node scripts/build-repo-map.mjs [options]
 *   node scripts/build-repo-map.mjs build   [--root <dir>] [--out <path>] [--quiet]
 *   node scripts/build-repo-map.mjs query   --files <f1,f2,...> [--root <dir>] [--out <path>] [--max-bytes <N>]
 *   node scripts/build-repo-map.mjs refresh --files <f1,f2,...> [--root <dir>] [--out <path>]
 *   node scripts/build-repo-map.mjs push    [--root <dir>] [--out <path>] [--branch <name>] [--quiet]
 *
 * Subcommands:
 *   build    Full (re)build of the map. Only re-summarizes entries whose blob
 *            hash changed or that are new. Unchanged entries are reused as-is.
 *            Default when no subcommand is given.
 *   query    Emit a ≤MAX_BYTES map slice for the given files and their directory
 *            neighbors. Used by work-on/build/context.md Phase C3.5.
 *   refresh  Incremental refresh: re-process only the given files. Used by
 *            work-on/close.md Phase C5.3 after a PR merge.
 *   push     Mirror the local map to the `forge-knowledge` orphan branch. Idempotent
 *            (force-push). Non-blocking when git remote is unavailable.
 *
 * Options:
 *   --root <dir>     Repo root (default: parent of this script's directory)
 *   --out <path>     Map JSON path (default: ~/.forge/index/repo-map.json)
 *   --files <list>   Comma- or space-separated file paths (relative to repo root)
 *   --max-bytes <N>  Max output bytes for `query` (default: 2048)
 *   --branch <name>  Orphan branch name for `push` (default: forge-knowledge)
 *   --quiet          Suppress informational output on stderr
 *   --help           Show this help
 *
 * Output format (repo-map.json):
 *   {
 *     "schema_version": 1,
 *     "built_at": "<ISO timestamp>",
 *     "repo": "<owner/repo from git remote or directory name>",
 *     "entries": {
 *       "<repo-relative POSIX path>": {
 *         "blob_hash": "<40-char git blob sha1>",
 *         "exports": ["<symbol>", ...],   // statically parsed, sorted
 *         "summary": "<one-liner>" | null // null until a model pass provides it
 *       }
 *     }
 *   }
 *
 * Supported file types for static export extraction:
 *   .mjs / .js    — export { X }, export default, export function, export const/let/var
 *   .sh / .bash   — public function declarations (name() { ... })
 *   .md           — ## headings used as structural landmarks
 *   others        — exports: [] (empty, no parsing attempt)
 */

import {
  readFileSync,
  writeFileSync,
  mkdirSync,
  readdirSync,
  statSync,
  existsSync,
} from "node:fs";
import { join, dirname, relative, basename, sep, posix } from "node:path";
import { fileURLToPath } from "node:url";
import { createHash } from "node:crypto";
import { execSync } from "node:child_process";
import { homedir } from "node:os";

const SCHEMA_VERSION = 1;
const DEFAULT_MAX_BYTES = 2048;
const DEFAULT_BRANCH = "forge-knowledge";

// ---------------------------------------------------------------------------
// Argument parsing
// ---------------------------------------------------------------------------

const rawArgs = process.argv.slice(2);
const SUBCOMMAND_SET = new Set(["build", "query", "refresh", "push"]);

let subcommand = "build";
const opts = {
  root: null,
  out: null,
  files: [],
  maxBytes: DEFAULT_MAX_BYTES,
  branch: DEFAULT_BRANCH,
  quiet: false,
};

// Consume subcommand token if present
let argOffset = 0;
if (rawArgs.length > 0 && SUBCOMMAND_SET.has(rawArgs[0])) {
  subcommand = rawArgs[0];
  argOffset = 1;
}

const args = rawArgs.slice(argOffset);
for (let i = 0; i < args.length; i++) {
  const a = args[i];
  if (a === "--help" || a === "-h") {
    printHelp();
    process.exit(0);
  } else if (a === "--root") {
    opts.root = args[++i];
  } else if (a === "--out") {
    opts.out = args[++i];
  } else if (a === "--files") {
    // Accept comma-separated or space-separated (multiple --files flags merge)
    const val = args[++i] || "";
    opts.files.push(...val.split(/[\s,]+/).filter(Boolean));
  } else if (a === "--max-bytes") {
    opts.maxBytes = parseInt(args[++i], 10) || DEFAULT_MAX_BYTES;
  } else if (a === "--branch") {
    opts.branch = args[++i];
  } else if (a === "--quiet") {
    opts.quiet = true;
  } else if (!a.startsWith("--")) {
    // Positional: treat remaining non-flag args as file paths (for `query`/`refresh`)
    opts.files.push(a);
  } else {
    warn(`Unknown argument: ${a}`);
  }
}

function printHelp() {
  const self = readFileSync(fileURLToPath(import.meta.url), "utf8");
  const m = self.match(/\/\*\*([\s\S]*?)\*\//);
  if (m) {
    process.stdout.write(
      m[1]
        .split("\n")
        .map((l) => l.replace(/^\s*\*?/, "").trimEnd())
        .join("\n")
        .trim() + "\n",
    );
  }
}

function info(msg) {
  if (!opts.quiet) process.stderr.write(`[repo-map] ${msg}\n`);
}

function warn(msg) {
  process.stderr.write(`[repo-map] WARNING: ${msg}\n`);
}

// ---------------------------------------------------------------------------
// Path resolution
// ---------------------------------------------------------------------------

const SCRIPT_DIR = dirname(fileURLToPath(import.meta.url));
const ROOT = opts.root
  ? opts.root
  : dirname(SCRIPT_DIR); // scripts/ → repo root

const DEFAULT_OUT = join(homedir(), ".forge", "index", "repo-map.json");
const OUT = opts.out ? opts.out : DEFAULT_OUT;

// ---------------------------------------------------------------------------
// Filesystem helpers (zero-dependency recursive glob)
// ---------------------------------------------------------------------------

function toPosix(p) {
  return p.split(sep).join("/");
}

/** Recursively list files matching predicate(repoRelativePosixPath). Sorted. */
function walk(dir, predicate) {
  const out = [];
  let entries;
  try {
    entries = readdirSync(dir, { withFileTypes: true });
  } catch {
    return out;
  }
  for (const ent of entries) {
    const full = join(dir, ent.name);
    if (ent.isDirectory()) {
      if (ent.name === "node_modules" || ent.name.startsWith(".")) continue;
      out.push(...walk(full, predicate));
    } else if (ent.isFile()) {
      const rel = toPosix(relative(ROOT, full));
      if (predicate(rel)) out.push(rel);
    }
  }
  return out.sort();
}

function safeRead(absPath) {
  try {
    return readFileSync(absPath, "utf8");
  } catch {
    return "";
  }
}

// ---------------------------------------------------------------------------
// Git blob hash computation
// ---------------------------------------------------------------------------

/** Compute git blob hash for a file (sha1 of "blob <size>\0<content>"). */
function blobHash(absPath) {
  let content;
  try {
    content = readFileSync(absPath);
  } catch {
    return null;
  }
  const h = createHash("sha1");
  h.update(`blob ${content.length}\0`);
  h.update(content);
  return h.digest("hex");
}

/** Try to get blob hash from git object database (fast path). */
function blobHashViaGit(repoRelPath) {
  try {
    const result = execSync(
      `git -C ${JSON.stringify(ROOT)} ls-files -s -- ${JSON.stringify(repoRelPath)}`,
      { encoding: "utf8", stdio: ["pipe", "pipe", "pipe"], timeout: 5000 },
    );
    // Output: "<mode> <hash> <stage>\t<file>"
    const parts = result.trim().split(/\s+/);
    if (parts.length >= 2 && /^[0-9a-f]{40}$/.test(parts[1])) return parts[1];
  } catch {
    // fallback: compute manually
  }
  return blobHash(join(ROOT, repoRelPath));
}

// ---------------------------------------------------------------------------
// Static export / symbol extraction
// ---------------------------------------------------------------------------

/** Extract exported names from a .mjs/.js file via regex (zero deps). */
function extractJsExports(content) {
  const names = new Set();

  // export function Foo / export async function Foo
  for (const m of content.matchAll(/^export\s+(?:async\s+)?function\s+(\w+)/gm)) {
    names.add(m[1]);
  }
  // export const/let/var Foo
  for (const m of content.matchAll(/^export\s+(?:const|let|var)\s+(\w+)/gm)) {
    names.add(m[1]);
  }
  // export class Foo
  for (const m of content.matchAll(/^export\s+class\s+(\w+)/gm)) {
    names.add(m[1]);
  }
  // export { Foo, Bar as Baz }
  for (const m of content.matchAll(/^export\s*\{([^}]+)\}/gm)) {
    for (const token of m[1].split(",")) {
      const name = token.trim().split(/\s+as\s+/).pop().trim();
      if (/^\w+$/.test(name) && name !== "default") names.add(name);
    }
  }
  // export default — record as "default"
  if (/^export\s+default\b/m.test(content)) names.add("default");

  return [...names].sort();
}

/** Extract public function names from a .sh file. */
function extractShFunctions(content) {
  const names = new Set();
  // name() { or name () {
  for (const m of content.matchAll(/^([a-zA-Z_][a-zA-Z0-9_]*)\s*\(\s*\)\s*\{/gm)) {
    names.add(m[1]);
  }
  // function name {
  for (const m of content.matchAll(/^function\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*[({]/gm)) {
    names.add(m[1]);
  }
  return [...names].sort();
}

/** Extract ## headings from a .md file as structural landmarks. */
function extractMdHeadings(content) {
  const names = [];
  for (const m of content.matchAll(/^#{1,3}\s+(.+)$/gm)) {
    const heading = m[1].trim().replace(/\s+/g, " ");
    if (heading.length > 0 && heading.length <= 80) names.push(heading);
  }
  return names.slice(0, 10); // cap at 10 headings
}

/** Dispatch to type-specific extractor. */
function extractExports(relPath, content) {
  if (relPath.endsWith(".mjs") || relPath.endsWith(".js")) {
    return extractJsExports(content);
  }
  if (relPath.endsWith(".sh") || relPath.endsWith(".bash")) {
    return extractShFunctions(content);
  }
  if (relPath.endsWith(".md")) {
    return extractMdHeadings(content);
  }
  return [];
}

// ---------------------------------------------------------------------------
// Repo identity
// ---------------------------------------------------------------------------

function getRepoIdentity() {
  try {
    const url = execSync(`git -C ${JSON.stringify(ROOT)} remote get-url origin`, {
      encoding: "utf8",
      stdio: ["pipe", "pipe", "pipe"],
      timeout: 3000,
    }).trim();
    // Extract owner/repo from https or ssh remote URL
    const m = url.match(/[:/]([^/]+\/[^/]+?)(?:\.git)?$/);
    if (m) return m[1];
  } catch {
    // ignore
  }
  return basename(ROOT);
}

// ---------------------------------------------------------------------------
// Map I/O
// ---------------------------------------------------------------------------

/** Load existing map from OUT path. Returns a default empty map on miss. */
function loadMap() {
  try {
    const raw = readFileSync(OUT, "utf8");
    const parsed = JSON.parse(raw);
    if (parsed && parsed.schema_version === SCHEMA_VERSION && parsed.entries) {
      return parsed;
    }
  } catch {
    // missing or corrupted — start fresh
  }
  return {
    schema_version: SCHEMA_VERSION,
    built_at: new Date().toISOString(),
    repo: getRepoIdentity(),
    entries: {},
  };
}

/** Save map to OUT, creating parent directories as needed. */
function saveMap(map) {
  map.built_at = new Date().toISOString();
  mkdirSync(dirname(OUT), { recursive: true });
  // Deterministic: sort entries by key
  const sorted = {
    schema_version: map.schema_version,
    built_at: map.built_at,
    repo: map.repo,
    entries: Object.fromEntries(
      Object.entries(map.entries).sort(([a], [b]) => a.localeCompare(b)),
    ),
  };
  writeFileSync(OUT, JSON.stringify(sorted, null, 2) + "\n", "utf8");
}

// ---------------------------------------------------------------------------
// Core: process a single file entry
// ---------------------------------------------------------------------------

/**
 * Build or update the map entry for one repo-relative file path.
 * Returns { updated: bool, entry: {...} }.
 * If the blob hash matches the existing entry, returns existing entry unchanged.
 */
function processFile(relPath, existingEntries) {
  const absPath = join(ROOT, relPath);
  const hash = blobHashViaGit(relPath) || blobHash(absPath);
  if (!hash) return null;

  const existing = existingEntries[relPath];
  if (existing && existing.blob_hash === hash) {
    // Cache hit — blob unchanged, reuse entry
    return { updated: false, entry: existing };
  }

  // Cache miss or new file — rebuild structural fields
  const content = safeRead(absPath);
  const exports = extractExports(relPath, content);

  const entry = {
    blob_hash: hash,
    exports,
    // summary is nullable — preserved from existing if blob matches (handled above)
    // on hash change, summary is reset to null (content changed, prior summary stale)
    summary: null,
  };

  return { updated: true, entry };
}

// ---------------------------------------------------------------------------
// Discover codebase files (not spec corpus — that's build-spec-graph.mjs)
// ---------------------------------------------------------------------------

const CODEBASE_EXTENSIONS = new Set([
  ".mjs", ".js", ".cjs",
  ".ts", ".tsx",
  ".py",
  ".sh", ".bash",
  ".go",
  ".rs",
  ".rb",
  ".java",
]);
const CODEBASE_MD_DIRS = new Set(["docs", "devdocs", "templates"]);

function isCodebaseFile(relPath) {
  const ext = relPath.match(/\.[^.]+$/)?.[0] ?? "";
  if (CODEBASE_EXTENSIONS.has(ext)) return true;
  // Include .md files from docs/devdocs/templates but not commands/
  if (ext === ".md") {
    const topDir = relPath.split("/")[0];
    return CODEBASE_MD_DIRS.has(topDir);
  }
  return false;
}

function discoverCodebaseFiles() {
  return walk(ROOT, (rel) => {
    // Exclude hidden dirs, node_modules, and binary/generated artifacts
    if (rel.startsWith(".")) return false;
    if (rel.includes("/node_modules/")) return false;
    if (rel.includes("/.claude/")) return false;
    if (rel.includes("/dist/")) return false;
    if (rel.includes("/__pycache__/")) return false;
    return isCodebaseFile(rel);
  });
}

// ---------------------------------------------------------------------------
// Subcommand: build
// ---------------------------------------------------------------------------

function cmdBuild() {
  const files = discoverCodebaseFiles();
  info(`Scanning ${files.length} codebase files…`);

  const map = loadMap();
  let updated = 0;
  let reused = 0;

  for (const relPath of files) {
    const result = processFile(relPath, map.entries);
    if (!result) continue;
    map.entries[relPath] = result.entry;
    if (result.updated) updated++;
    else reused++;
  }

  // Remove entries for files that no longer exist
  const fileSet = new Set(files);
  let removed = 0;
  for (const key of Object.keys(map.entries)) {
    if (!fileSet.has(key)) {
      delete map.entries[key];
      removed++;
    }
  }

  saveMap(map);
  info(`Build complete: ${updated} updated, ${reused} reused, ${removed} removed → ${OUT}`);
  if (!opts.quiet) {
    process.stdout.write(
      JSON.stringify({ updated, reused, removed, total: Object.keys(map.entries).length }) + "\n",
    );
  }
}

// ---------------------------------------------------------------------------
// Subcommand: query
// ---------------------------------------------------------------------------

/**
 * Emit a ≤maxBytes map slice for the given files and their directory neighbors.
 * Output is a compact text block (not JSON) optimized for injection into a
 * FORGE:CONTEXT comment.
 *
 * Format per line:
 *   <relpath> — <exports joined by ", " or "(no exports)"> — <summary or "summary pending">
 */
function cmdQuery() {
  if (opts.files.length === 0) {
    warn("query requires --files <list>");
    process.exit(1);
  }

  const map = loadMap();
  const entries = map.entries;

  // Normalize requested file paths to repo-relative POSIX
  const requested = new Set(
    opts.files.map((f) => toPosix(relative(ROOT, join(ROOT, f)))),
  );

  // Expand to directory neighbors
  const neighborDirs = new Set([...requested].map((f) => posix.dirname(f)));
  const candidates = new Map();

  for (const [rel, entry] of Object.entries(entries)) {
    const inRequested = requested.has(rel);
    const inNeighborDir = neighborDirs.has(posix.dirname(rel));
    if (inRequested || inNeighborDir) {
      // Priority: requested files first (lower sort key), then neighbors
      candidates.set(rel, { entry, priority: inRequested ? 0 : 1 });
    }
  }

  // Sort: requested first, then by path
  const sorted = [...candidates.entries()].sort(([a, ai], [b, bi]) => {
    if (ai.priority !== bi.priority) return ai.priority - bi.priority;
    return a.localeCompare(b);
  });

  // Build output, honoring maxBytes
  const lines = [];
  let totalBytes = 0;
  for (const [rel, { entry }] of sorted) {
    const exportsStr =
      entry.exports && entry.exports.length > 0
        ? entry.exports.slice(0, 8).join(", ") + (entry.exports.length > 8 ? ", …" : "")
        : "(no exports)";
    const summaryStr = entry.summary || "summary pending";
    const line = `${rel} — exports: ${exportsStr} — ${summaryStr}`;
    const lineBytes = Buffer.byteLength(line, "utf8") + 1; // +1 for newline
    if (totalBytes + lineBytes > opts.maxBytes && lines.length > 0) break;
    lines.push(line);
    totalBytes += lineBytes;
  }

  if (lines.length === 0) {
    // Map may not be built yet — emit a skip note
    process.stdout.write("(repo map not built — run: node scripts/build-repo-map.mjs build)\n");
  } else {
    process.stdout.write(lines.join("\n") + "\n");
  }
}

// ---------------------------------------------------------------------------
// Subcommand: refresh
// ---------------------------------------------------------------------------

function cmdRefresh() {
  if (opts.files.length === 0) {
    warn("refresh requires --files <list>");
    process.exit(1);
  }

  const map = loadMap();
  let updated = 0;
  let skipped = 0;

  for (const rawPath of opts.files) {
    const relPath = toPosix(relative(ROOT, join(ROOT, rawPath)));
    const absPath = join(ROOT, relPath);

    if (!existsSync(absPath)) {
      // File deleted — remove from map
      if (map.entries[relPath]) {
        delete map.entries[relPath];
        updated++;
        info(`Removed deleted file: ${relPath}`);
      }
      continue;
    }

    const result = processFile(relPath, map.entries);
    if (!result) {
      warn(`Could not process: ${relPath}`);
      continue;
    }

    if (result.updated) {
      map.entries[relPath] = result.entry;
      updated++;
      info(`Refreshed: ${relPath} (blob hash changed)`);
    } else {
      skipped++;
      info(`Skipped: ${relPath} (blob hash unchanged)`);
    }
  }

  saveMap(map);
  info(`Refresh complete: ${updated} updated, ${skipped} skipped (blob hash unchanged) → ${OUT}`);
  if (!opts.quiet) {
    process.stdout.write(JSON.stringify({ updated, skipped }) + "\n");
  }
}

// ---------------------------------------------------------------------------
// Subcommand: push
// ---------------------------------------------------------------------------

function cmdPush() {
  if (!existsSync(OUT)) {
    warn(`Map not found at ${OUT} — run 'build' first`);
    process.exit(1);
  }

  const branch = opts.branch;
  const mapContent = readFileSync(OUT, "utf8");

  try {
    // Check if git is available and we're in a git repo
    execSync(`git -C ${JSON.stringify(ROOT)} rev-parse --git-dir`, {
      stdio: "pipe",
      timeout: 3000,
    });
  } catch {
    warn("Not inside a git repository — skipping push");
    return;
  }

  // Check if remote origin is available
  try {
    execSync(`git -C ${JSON.stringify(ROOT)} ls-remote --exit-code origin HEAD`, {
      stdio: "pipe",
      timeout: 10000,
    });
  } catch {
    warn("Remote 'origin' not reachable — skipping push (local map is up to date)");
    return;
  }

  // Prepare a temporary index to build the orphan tree
  const tmpIndex = join(ROOT, ".forge", "tmp-push-index");
  mkdirSync(dirname(tmpIndex), { recursive: true });

  try {
    // Write the map content as a git blob
    const blobSha = execSync(
      `git -C ${JSON.stringify(ROOT)} hash-object -w --stdin`,
      {
        input: mapContent,
        encoding: "utf8",
        stdio: ["pipe", "pipe", "pipe"],
        timeout: 5000,
      },
    ).trim();

    // Build a tree with repo-map.json pointing to that blob
    const treeContent = `100644 blob ${blobSha}\trepo-map.json\n`;
    const treeSha = execSync(
      `git -C ${JSON.stringify(ROOT)} mktree`,
      {
        input: treeContent,
        encoding: "utf8",
        stdio: ["pipe", "pipe", "pipe"],
        timeout: 5000,
      },
    ).trim();

    // Create a commit on the orphan branch
    // Use the previous commit as parent if the branch already exists
    let parentFlag = "--orphan";
    let commitParent = "";
    try {
      const prevCommit = execSync(
        `git -C ${JSON.stringify(ROOT)} ls-remote origin ${branch}`,
        { encoding: "utf8", stdio: "pipe", timeout: 5000 },
      ).trim().split(/\s+/)[0];
      if (prevCommit) {
        commitParent = prevCommit;
      }
    } catch {
      // new branch
    }

    let commitSha;
    if (commitParent) {
      // Create commit with parent (update, not orphan)
      commitSha = execSync(
        `git -C ${JSON.stringify(ROOT)} commit-tree ${treeSha} -p ${commitParent} -m "chore(repo-map): update orientation index"`,
        { encoding: "utf8", stdio: ["pipe", "pipe", "pipe"], timeout: 5000 },
      ).trim();
    } else {
      // First commit on the orphan branch
      commitSha = execSync(
        `git -C ${JSON.stringify(ROOT)} commit-tree ${treeSha} -m "chore(repo-map): initial orientation index"`,
        { encoding: "utf8", stdio: ["pipe", "pipe", "pipe"], timeout: 5000 },
      ).trim();
    }

    // Force-push to origin
    execSync(
      `git -C ${JSON.stringify(ROOT)} push origin ${commitSha}:refs/heads/${branch} --force`,
      { stdio: ["pipe", "pipe", "pipe"], timeout: 30000 },
    );

    info(`Pushed map to origin/${branch} (commit ${commitSha.slice(0, 8)})`);
    if (!opts.quiet) {
      process.stdout.write(JSON.stringify({ pushed: true, branch, commit: commitSha }) + "\n");
    }
  } catch (err) {
    warn(`Push failed: ${err.message || err} — local map is still up to date`);
    // Non-blocking: exit 0 so calling specs continue
    if (!opts.quiet) {
      process.stdout.write(JSON.stringify({ pushed: false, error: String(err.message || err) }) + "\n");
    }
  }
}

// ---------------------------------------------------------------------------
// Dispatch
// ---------------------------------------------------------------------------

switch (subcommand) {
  case "build":
    cmdBuild();
    break;
  case "query":
    cmdQuery();
    break;
  case "refresh":
    cmdRefresh();
    break;
  case "push":
    cmdPush();
    break;
  default:
    warn(`Unknown subcommand: ${subcommand}`);
    printHelp();
    process.exit(2);
}
